#include <iostream>
using namespace std;
int main()
{ 
    int num1, num2, temp;
    temp = 0;
    cin >> num1 >> num2;
    cout << "Before swapping." << endl;
    cout << "number1 = " << num1 << ", number2 = " << num2 << endl;

    if (num1 > num2)
    { 
        temp = num1;
        num1 = num2;
        num2 = temp;
        cout << "\nAfter swapping." << endl;
        cout << "number1 = " << num1 << ", number2 = " << num2 << endl; 
    }
    else
        cout << "num1 is less than num2" << endl;

    return 0; 
}

#include <iostream>
using namespace std;
int main() { 
    int n;
    cout << "Enter an integer: ";
    cin >> n;

    // Using if..else
    if (n % 2 == 0)
        cout << n << " is even.";
    else
        cout << n << " is odd.";

    // Using ternary operator
    (n % 2 == 0) ? cout << n << " is even." : cout << n << " is odd.";

    return 0; 
}

