#include<iostream>
using namespace std;
int main()
{
    int a[10], even[10], odd[10], i, j = 0, k = 0;

    for(i = 0; i < 10; i++)
        cin >> a[i];

    for(i = 0; i < 10; i++)
    {
        if(a[i] % 2 == 0)
            even[j++] = a[i];
        else
            odd[k++] = a[i];
    }

    for(i = 0; i < j; i++)
        cout << even[i] << " ";
    cout << endl;

    for(i = 0; i < k; i++)
        cout << odd[i] << " ";

    return 0;
}

